import { createClient } from '@supabase/supabase-js';

const supabaseUrl = 'https://your-supabase-url.supabase.co';
const supabaseKey = 'your-supabase-key';
const supabase = createClient(supabaseUrl, supabaseKey);

export async function exportTimePunches(startDate, endDate, teamCode) {
  const { data: timePunches, error } = await supabase
    .from('time_punches')
    .select('*')
    .gte('punch_time', startDate.toISOString())
    .lte('punch_time', endDate.toISOString())
    .eq('team_code', teamCode);

  if (error) {
    throw new Error(`Error fetching time punches: ${error.message}`);
  }

  const csvContent = 'data:text/csv;charset=utf-8,';
  const headers = ['id', 'user_id', 'punch_time', 'team_code'];
  const rows = [headers.join(',')];

  timePunches.forEach(timePunch => {
    const row = [
      timePunch.id,
      timePunch.user_id,
      timePunch.punch_time.toISOString(),
      timePunch.team_code
    ];
    rows.push(row.join(','));
  });

  return `${csvContent}${rows.join('\n')}`;
}
